#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,w,s[601]={0},m,a,b;
    cin>>n>>w;
    for (int i=1;i<=n;i++){
        cin>>a;
        s[a]++;
        m=max(1,i*w/100);
        b=0;
        for (int j=600;j>=0;j--){
            b+=s[j];
            if (b>=m){
                cout<<j<<" ";
                break;
            }
        }
    }
    return 0;
}
